using Microsoft.AspNetCore.Identity;

namespace sv_93a38292c6614621bcd28e9cbe5b7175.Data;

public class ApplicationUser : IdentityUser
{
}

using Microsoft.AspNetCore.Identity.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore;

namespace sv_93a38292c6614621bcd28e9cbe5b7175.Data;

public class ApplicationDbContext : IdentityDbContext<ApplicationUser>
{
    public ApplicationDbContext(DbContextOptions<ApplicationDbContext> options)
        : base(options)
    {
    }
}

@inject NavigationManager Navigation

@code {
    protected override void OnInitialized()
    {
        Navigation.NavigateTo($"Account/Login?returnUrl={Uri.EscapeDataString(Navigation.Uri)}", forceLoad: true);
    }
}

@page "/Account/Login"
@using Microsoft.AspNetCore.Identity
@using sv_93a38292c6614621bcd28e9cbe5b7175.Data
@inject SignInManager<ApplicationUser> SignInManager
@inject NavigationManager Navigation

<PageTitle>Log in</PageTitle>

<div class="row justify-content-center">
    <div class="col-md-4">
        <h1>Log in</h1>

        @if (!string.IsNullOrEmpty(errorMessage))
        {
            <div class="alert alert-danger">@errorMessage</div>
        }

        <form method="post" @formname="login" @onsubmit="LoginUser">
            <AntiforgeryToken />
            <div class="mb-3">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" @bind="email" required />
            </div>
            <div class="mb-3">
                <label class="form-label">Password</label>
                <input type="password" class="form-control" @bind="password" required />
            </div>
            <button type="submit" class="btn btn-primary w-100">Log in</button>
        </form>
    </div>
</div>

@code {
    [SupplyParameterFromForm] private string email { get; set; } = "";
    [SupplyParameterFromForm] private string password { get; set; } = "";
    [SupplyParameterFromQuery] private string? returnUrl { get; set; }

    private string? errorMessage;

    private async Task LoginUser()
    {
        var result = await SignInManager.PasswordSignInAsync(email, password, isPersistent: false, lockoutOnFailure: false);
        if (result.Succeeded)
        {
            Navigation.NavigateTo(returnUrl ?? "/", forceLoad: true);
        }
        else
        {
            errorMessage = "Invalid email or password.";
        }
    }
}

@page "/Account/Logout"
@using Microsoft.AspNetCore.Identity
@using sv_93a38292c6614621bcd28e9cbe5b7175.Data
@inject SignInManager<ApplicationUser> SignInManager
@inject NavigationManager Navigation

<PageTitle>Logging out...</PageTitle>

@code {
    protected override async Task OnInitializedAsync()
    {
        await SignInManager.SignOutAsync();
        Navigation.NavigateTo("/", forceLoad: true);
    }
}

@page "/admin/users"
@rendermode InteractiveServer
@attribute [Authorize(Roles = "Admin")]
@using Microsoft.AspNetCore.Identity
@using sv_93a38292c6614621bcd28e9cbe5b7175.Data
@inject UserManager<ApplicationUser> UserManager

<PageTitle>User Management</PageTitle>

<h1>User Management</h1>
<p>All registered users and their roles.</p>

@if (userRoles is null)
{
    <p><em>Loading...</em></p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Email</th>
                <th>Roles</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var (user, roles) in userRoles)
            {
                <tr>
                    <td>@user.Email</td>
                    <td>@string.Join(", ", roles)</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<(ApplicationUser User, IList<string> Roles)>? userRoles;

    protected override async Task OnInitializedAsync()
    {
        var users = UserManager.Users.ToList();
        var result = new List<(ApplicationUser, IList<string>)>();
        foreach (var user in users)
        {
            var roles = await UserManager.GetRolesAsync(user);
            result.Add((user, roles));
        }
        userRoles = result;
    }
}

